import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { calculateBMI, getBMICategory } from '../../utils/calculations';
import './BMIcalculator.css';

const BMIcalculator = () => {
  const [weight, setWeight] = useState('');
  const [height, setHeight] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const handleWeightChange = (e) => {
    const value = e.target.value;
    if (value === '' || /^\d*\.?\d*$/.test(value)) {
      setWeight(value);
      setError('');
    }
  };

  const handleHeightChange = (e) => {
    const value = e.target.value;
    if (value === '' || /^\d*\.?\d*$/.test(value)) {
      setHeight(value);
      setError('');
    }
  };

  const handleCalculate = () => {
    if (!weight || !height) {
      setError('Please enter both weight and height');
      return;
    }

    const weightNum = parseFloat(weight);
    const heightNum = parseFloat(height);

    if (weightNum <= 0 || heightNum <= 0) {
      setError('Weight and height must be positive numbers');
      return;
    }

    if (weightNum > 300) {
      setError('Weight seems too high (max 300 kg)');
      return;
    }

    if (heightNum > 300) {
      setError('Height seems too high (max 300 cm)');
      return;
    }

    const bmiValue = calculateBMI(weightNum, heightNum);
    const bmiCategory = getBMICategory(bmiValue);

    navigate('/result', {
      state: {
        bmi: bmiValue,
        category: bmiCategory,
        weight: weightNum,
        height: heightNum
      }
    });
  };

  const handleReset = () => {
    setWeight('');
    setHeight('');
    setError('');
  };

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <div className="bmi-calculator">
      <div className="header-with-logout">
        <h1 className="bmi-title">BMI Calculator</h1>
        <div className="user-info">
          <span className="user-name">Hi, {user?.name || 'User'}!</span>
          <button onClick={handleLogout} className="logout-btn">
            Logout
          </button>
        </div>
      </div>

      <p className="bmi-subtitle">Check your Body Mass Index</p>

      <div className="input-group">
        <label htmlFor="weight">Weight (kg):</label>
        <input
          type="text"
          id="weight"
          value={weight}
          onChange={handleWeightChange}
          placeholder="Enter your weight"
          className="bmi-input"
        />
      </div>

      <div className="input-group">
        <label htmlFor="height">Height (cm):</label>
        <input
          type="text"
          id="height"
          value={height}
          onChange={handleHeightChange}
          placeholder="Enter your height"
          className="bmi-input"
        />
      </div>

      {error && <div className="error-message">{error}</div>}

      <div className="button-group">
        <button onClick={handleCalculate} className="calculate-btn">
          Check Your BMI
        </button>
        <button onClick={handleReset} className="reset-btn">
          Clear
        </button>
      </div>

      <div className="info-box">
        <p>📊 Enter your details to get instant results</p>
        <p>📋 Get personalized health tips</p>
      </div>
    </div>
  );
};

export default BMIcalculator;
